    fn tokenToSymbol(self: *Parser, token: Token) u16 {
        return switch (token.cat) {
            .@"eof" => 1,
            .@"ident" => self.identToSymbol(token),
            .@"newline" => 55,
            .@"string_sq" => 60,
            .@"string_dq" => 61,
            .@"indent" => 66,
            .@"outdent" => 67,
            .@"integer" => 89,
            .@"post_if" => 105,
            .@"minus_prefix" => 117,
            .@"real" => 127,
            .@"true" => 128,
            .@"false" => 129,
            .@"colon" => 56,
            .@"assign" => 72,
            .@"comma" => 78,
            .@"not_sym" => 82,
            .@"question" => 83,
            .@"star" => 84,
            .@"lbracket" => 87,
            .@"rbracket" => 88,
            .@"bar" => 92,
            .@"dot" => 99,
            .@"ampersand" => 119,
            .@"tilde" => 120,
            .@"lparen" => 123,
            .@"rparen" => 124,
            .@"at" => 133,
            .@"lbrace" => 134,
            .@"rbrace" => 137,
            .@"caret" => 157,
            .@"lt" => 160,
            .@"gt" => 161,
            .@"plus" => 166,
            .@"minus" => 167,
            .@"slash" => 168,
            .@"percent" => 169,
            .@"arrow" => 81,
            .@"dotdot" => 100,
            .@"fat_arrow" => 101,
            .@"nullish" => 102,
            .@"plus_assign" => 112,
            .@"minus_assign" => 113,
            .@"star_assign" => 114,
            .@"slash_assign" => 115,
            .@"const_assign" => 116,
            .@"pipe" => 154,
            .@"or_sym" => 155,
            .@"and_sym" => 156,
            .@"eq" => 158,
            .@"ne" => 159,
            .@"le" => 162,
            .@"ge" => 163,
            .@"lshift" => 164,
            .@"rshift" => 165,
            .@"power" => 170,
            else => 2, // error
        };
    }

    fn identToSymbol(self: *Parser, token: Token) u16 {
        const text = self.source[token.pos..][0..token.len];
        if (text.len == 0) return SYM_IDENT;
        if (self.try_ident_as_keyword(token, text)) |sym| return sym;
        return SYM_IDENT;
    }

    fn try_ident_as_keyword(self: *Parser, token: Token, text: []const u8) ?u16 {
        _ = token;
        const state = self.state_stack.getLast();
        if (rip.keyword_as(text)) |id| {
            const id_idx = @intFromEnum(id);
            const sym = keyword_to_symbol[id_idx];
            if (sym != 0 and getAction(state, sym) != 0) {
                self.last_matched_id = @intCast(id_idx);
                return sym;
            }
            const fallback = keyword_fallback_symbol;
            if (fallback != 0 and getAction(state, fallback) != 0) {
                self.last_matched_id = @intCast(id_idx);
                return fallback;
            }
        }
        return null;
    }

    pub fn parseProgram(self: *Parser) !Sexp {
        self.injected_token = SYM_program_START;
        return self.doParse(SYM_program);
    }
    pub fn parseExpr(self: *Parser) !Sexp {
        self.injected_token = SYM_expr_START;
        return self.doParse(SYM_expr);
    }
};

